module top_module(
  input CLK,
  input EN,
  input TE,
  input reset,
  output ENCLK
);reg clk_gating_ENCLK_reg;

  always @(posedge CLK, posedge reset) begin
    if (reset) begin
      clk_gating_ENCLK_reg <= 1'b0;
    end else if (EN && TE) begin
      clk_gating_ENCLK_reg <= ~clk_gating_ENCLK_reg;
    end
  end

  assign ENCLK = clk_gating_ENCLK_reg;

endmodule
